+        raw.add(1).write(b'Y');
+    }
+
+    let result = unsafe { qgcvt(123.456, libc::c_int::MAX, raw.cast::<libc::c_char>()) };
+
+    assert_eq!(result.cast::<u8>(), raw);
+    assert_eq!(unsafe { raw.add(1).read() }, 0);
+    unsafe { frankenlibc_abi::malloc_abi::free(raw.cast()) };
+}
